############################################################ # PG Setup Code ############################################################ $decimal = random(0.01,0.03,0.001); Context("Currency")->flags->set(trimTrailingZeros => 1, tolerance => 0.5); $final = 1400 + random(-300, 300, 10); $current = Currency($final); $solution = $final/(1 + $decimal); $before = Currency($solution); Context("Percent"); $percent = Percent($decimal);
############################################################ # Body ############################################################
BEGIN_PGML One year, the median rent for a one-bedroom apartment in a city was reported to be [`[$current]\text{.}`] This was reported to be an increase of [`[$percent]`] over the previous year. Based on this reporting, what was the median rent for of a one-bedroom apartment the previous year?
[_]{$before}{20}
END_PGML
